parameters.query:
=DECLARE @new_signal_id UNIQUEIDENTIFIER = NEWID();
INSERT INTO signal_events (signal_id, source_channel, raw_payload, status, delete_flag, record_version)
VALUES (@new_signal_id, 'RSS', '{{ JSON.stringify($json) }}', 'INGESTED', 'N', 1);
SELECT @new_signal_id AS signal_id;

=DECLARE @matched_id VARCHAR(50);

SELECT TOP 1 @matched_id = e.entity_id 
FROM enterprise_entities e 
WHERE e.delete_flag = 'N' AND e.is_active = 1 AND '{{ $node["RSS Trigger (Sense)"].json.title }}' LIKE '%' + e.entity_name + '%';

IF @matched_id IS NULL SET @matched_id = 'ENT_001';

SELECT TOP 1 e.*, m.resolution_pattern, m.policy_constraints, m.business_rule_applied 
FROM enterprise_entities e 
LEFT JOIN enterprise_memory m ON e.entity_id = m.entity_id AND m.delete_flag = 'N'
WHERE e.entity_id = @matched_id;

